from typing import List

from langchain_core.language_models import BaseChatModel
from langchain_core.messages import HumanMessage
from pydantic import BaseModel, Field
from src.models.llm import deepseek_llm
from utils.logger_handler import logger
from core.settings import settings
from src.config.llm_config import LLMService
from src.prompts.rag.qa_generation import QA_GENERATION_PROMPT
from utils.utils import get_current_time


class QaData(BaseModel):
    question:str = Field(...,description="问题")
    answer:str = Field(...,description="答案")
    language:str = Field(...,description="语言")
    difficulty:str = Field(...,description="难度")
    intent:str = Field(...,description="意图")
    node_ids:List[str] = Field(...,description="涉及的node_id列表")

class  QAResult(BaseModel):
    """QA数据构建助手返回的数据"""
    qa_list:List[QaData] = Field(...,description="QA列表")

def generate_qa(llm:BaseChatModel, nodes, metadata=None):

    prompt = QA_GENERATION_PROMPT.format(nodes=nodes)
    node_ids = [node['node_id'] for node in nodes]

    for i in range(settings.max_retries):
        try:
            llm = llm.with_structured_output(QAResult)
            response = llm.invoke([HumanMessage(content=prompt)])
            print(response)
            qa_list = []
            create_time = get_current_time()
            for item in response.qa_list:
                if not item.question or not item.answer or not isinstance(item.node_ids,list) or not item.node_ids:
                    continue
                step = False
                for node_id in item.node_ids:
                    if node_id not in node_ids:
                        step = True
                if step:
                    continue
                qa_list.append({
                    "question": item.question,
                    "answer": item.answer,
                    "language": item.language,
                    "difficulty": item.difficulty,
                    "intent": item.intent,
                    "metadata": metadata,
                    "node_ids":item.node_ids,
                    "create_time":create_time,
                    "state":0  # 0代表未评估，1代表评估过
                })

            return qa_list
        except Exception as e:
            logger.warning(f"[LLM失败] 第{i + 1}次: {e}")
            pass
    logger.error(f"QA构建数据失败：f{nodes}")
    return []


